text:
@keyframes skeleton-fade {
  0%,
  100% {
    opacity: 0.4;
  }

  50% {
    opacity: 1;
  }
}

.root {
  height: var(--skeleton-height, auto);
  width: var(--skeleton-width, 100%);
  border-radius: var(--skeleton-radius, var(--mantine-radius-default));
  position: relative;
  transform: translateZ(0);
  -webkit-transform: translateZ(0);

  &:where([data-animate])::after {
    animation: skeleton-fade 1500ms linear infinite;
  }

  &:where([data-visible]) {
    overflow: hidden;

    &::before {
      position: absolute;
      content: '';
      inset: 0;
      z-index: 10;
      background-color: var(--mantine-color-body);
    }

    &::after {
      position: absolute;
      content: '';
      inset: 0;
      z-index: 11;

      @mixin where-light {
        background-color: var(--mantine-color-gray-3);
      }

      @mixin where-dark {
        background-color: var(--mantine-color-dark-4);
      }
    }
  }
}

[data-respect-reduced-motion] {
  @media (prefers-reduced-motion: reduce) {
    [data-reduce-motion] {
      transition: none;
      animation: none;
    }
  }
}

.mantine-light-hidden {
  @mixin light {
    display: none;
  }
}

.mantine-dark-hidden {
  @mixin dark {
    display: none;
  }
}

.mantine-focus-auto {
  &:focus-visible {
    outline: 2px solid var(--mantine-primary-color-filled);
    outline-offset: 2px;
  }
}

.mantine-focus-always {
  &:focus {
    outline: 2px solid var(--mantine-primary-color-filled);
    outline-offset: 2px;
  }
}

.mantine-focus-never {
  &:focus {
    outline: none;
  }
}

.mantine-active {
  &:active {
    transform: translateY(rem(1px));
  }

  fieldset:disabled &:active {
    transform: none;
  }
}

.mantine-rotate-rtl {
  @mixin where-rtl {
    transform: rotate(180deg);
  }
}

@layer components {
  .SkipNav {
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    overflow: hidden;
    white-space: nowrap;
    border: 0;
    position: absolute;
    padding: 0;
    width: 1px;
    height: 1px;
    margin: -1px;

    &:focus-visible {
      clip: auto;
      clip-path: none;
      height: var(--header-height);
      overflow: visible;
      width: auto;
      white-space: normal;
      left: 0;
      z-index: 1;
      display: inline-flex;
      justify-content: center;
      align-items: center;
      padding-inline: 12px;
      background-color: var(--color-background);
      color: var(--color-blue);
      text-decoration: underline;
      text-underline-offset: 2px;
      text-decoration-thickness: 1px;
      text-decoration-color: color-mix(in oklab, var(--color-blue), transparent);
      outline: 2px solid var(--gray-t2);
      outline-offset: -2px;
      border-radius: var(--radius-4);
    }
  }
}
